SELECT qb.* FROM question_bank qb
WHERE qb.id IN (
    -- 从传统考试表获取题目
    SELECT eq.question_id FROM exam_question eq WHERE eq.exam_id = #{examId}
    UNION
    -- 从AI生成考试表获取题目
    SELECT aeq.question_bank_id FROM auto_exam_question aeq WHERE aeq.exam_id = #{examId}
)
ORDER BY qb.id

